from flatten_config import main

def test_flatten():
    config = {"a": {"b": 1, "c": {"d": 2}}, "e": [1, 2, 3]}

    # Test without prefix
    result1 = main(config)
    print(f"Result 1: {result1}")
    assert result1 == {"a.b": 1, "a.c.d": 2, "e": [1, 2, 3]}

    # Test with prefix
    result2 = main(config, prefix="ns")
    print(f"Result 2: {result2}")
    assert result2 == {"ns.a.b": 1, "ns.a.c.d": 2, "ns.e": [1, 2, 3]}

    print("All tests passed!")

